final:
module NoiseSuppression(  
    input [4:0] noise_free_signal,  
    output reg signal_out  
);  
    always @(*) begin  
        if ((noise_free_signal[0] + noise_free_signal[1] + noise_free_signal[2] + noise_free_signal[3] + noise_free_signal[4]) >= 3)  
            signal_out = 1;  
        else  
            signal_out = 0;  
    end  
endmodule
